import React, { useState } from "react";

function App() {
  const [file, setFile]       = useState(null);
  const [result, setResult]   = useState("");
  const [loading, setLoading] = useState(false);
  const [preview, setPreview] = useState(null);   // image preview

  // ✅ Handle file selection + show preview
  const handleFileChange = (e) => {
    const selected = e.target.files[0];
    setFile(selected);
    setResult("");

    if (selected) {
      setPreview(URL.createObjectURL(selected));  // show image preview
    }
  };

  const handleUpload = async () => {

    // ✅ Fix 1: Guard against null file
    if (!file) {
      alert("Please select an image first!");
      return;
    }

    setLoading(true);
    setResult("");

    try {
      // ✅ Fix 2: Proper FormData
      const formData = new FormData();
      formData.append("file", file);

      // ✅ Fix 3: Explicit POST with error checking
      const response = await fetch("http://127.0.0.1:5000/predict", {
        method: "POST",
        body: formData,
      });

      // ✅ Fix 4: Check HTTP status before parsing
      if (!response.ok) {
        throw new Error(`Server error: ${response.status}`);
      }

      const data = await response.json();

      setResult(
        `${data.prediction} (Confidence: ${data.value.toFixed(3)})`
      );

    // ✅ Fix 5: Catch network/fetch errors clearly
    } catch (err) {
      console.error("Prediction error:", err);
      if (err.message.includes("Failed to fetch")) {
        setResult("❌ Cannot reach Flask. Is python app.py running?");
      } else {
        setResult(`❌ Error: ${err.message}`);
      }
    } finally {
      setLoading(false);   // ✅ Always stop loading
    }
  };

  return (
    <div style={{ textAlign: "center", marginTop: "50px", fontFamily: "Arial" }}>

      <h1></h1>

      {/* ✅ Accept images only */}
      <input
        type="file"
        accept="image/*"
        onChange={handleFileChange}
      />

      <br /><br />

      {/* ✅ Show image preview */}
      {preview && (
        <img
          src={preview}
          alt="Preview"
          style={{ width: "300px", borderRadius: "10px", marginBottom: "15px" }}
        />
      )}

      <br />

      {/* ✅ Disable button while loading */}
      <button
        onClick={handleUpload}
        disabled={loading}
        style={{ padding: "10px 25px", fontSize: "16px", cursor: "pointer" }}
      >
        {loading ? "⏳ Predicting..." : "Predict"}
      </button>

      {/* ✅ Show result or error */}
      {result && (
        <h2 style={{ color: result.startsWith("❌") ? "red" : "green" }}>
          {result}
        </h2>
      )}

    </div>
  );
}

export default App;
